import{c as e,cG as a,cb as o,c8 as t,cf as n,cT as d,ce as l}from"./chunks/framework.BlkIsu1j.js";const r=JSON.parse('{"title":"附录 G：术语表","description":"","frontmatter":{"title":"附录 G：术语表","outline":"deep","layout":"doc","prev":"/ai/claudecodenew/appendix-f-troubleshooting","next":false,"date":"2026-05-30T10:00:00.000Z"},"headers":[],"relativePath":"ai/claudecodenew/appendix-g-glossary.md","filePath":"ai/claudecodenew/appendix-g-glossary.md","lastUpdated":1780121796000}'),i={id:"frontmatter-title",tabindex:"-1"};const h=e({name:"ai/claudecodenew/appendix-g-glossary.md"},[["render",function(e,r,h,c,s,p){return a(),o("div",null,[t("h1",i,[n(d(e.$frontmatter.title)+" ",1),r[0]||(r[0]=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),r[1]||(r[1]=l('<p>本术语表按英文术语的字母顺序排列，涵盖了本书中出现的所有关键概念。每个条目包含术语的英文原名、中文译名及简要定义，方便读者在阅读过程中快速查阅。</p><hr><h2 id="agent-智能代理" tabindex="-1">Agent / 智能代理 <a class="header-anchor" href="#agent-智能代理" aria-label="Permalink to “Agent / 智能代理”">​</a></h2><p>Claude Code 本身就是一个 Agent——它不是 AI 模型，而是一个能够自主规划、调用工具、管理上下文并协调模型通信的软件框架。Agent 负责对话管理、工具调用、权限控制、上下文维护和模型调度五大核心职责。与传统的&quot;输入-输出&quot;聊天机器人不同，Agent 可以主动执行多步骤任务，在遇到问题时自行调整策略，是人类开发者的协作伙伴而非简单的代码补全工具。</p><h2 id="agent-loop-代理循环" tabindex="-1">Agent Loop / 代理循环 <a class="header-anchor" href="#agent-loop-代理循环" aria-label="Permalink to “Agent Loop / 代理循环”">​</a></h2><p>Agent 执行任务时的核心工作循环，包括四个阶段：理解任务意图、制定执行计划、调用工具执行、评估结果并迭代。每完成一轮工具调用，Agent 会将结果反馈给模型，模型判断是否需要继续执行下一轮，直到任务完成或遇到阻塞。Agent Loop 是 Claude Code 能够自主完成复杂任务的关键机制，也是区别于普通问答式 AI 的根本特征。</p><h2 id="agentic-coding-代理式编程" tabindex="-1">Agentic Coding / 代理式编程 <a class="header-anchor" href="#agentic-coding-代理式编程" aria-label="Permalink to “Agentic Coding / 代理式编程”">​</a></h2><p>一种全新的编程范式，开发者从&quot;亲手写每一行代码&quot;转变为&quot;定义目标、审查结果、提供反馈&quot;。在代理式编程中，开发者以架构师和审查者的角色与 AI Agent 协作，Agent 负责具体的代码编写、测试、调试和部署工作。这种范式不仅提升了开发效率，更改变了开发者与代码的关系——代码变成了可对话、可协商的产物。</p><h2 id="api-key-api-密钥" tabindex="-1">API Key / API 密钥 <a class="header-anchor" href="#api-key-api-密钥" aria-label="Permalink to “API Key / API 密钥”">​</a></h2><p>用于认证和授权访问 AI 模型服务（如 Anthropic API、DeepSeek API）的密钥字符串。Claude Code 通过 API Key 与底层模型通信，密钥的权限范围决定了 Agent 可以调用哪些模型和能力。妥善管理 API Key（如使用环境变量、避免硬编码到项目中）是安全使用 Claude Code 的基本要求。</p><h2 id="cc-switch" tabindex="-1">cc-switch <a class="header-anchor" href="#cc-switch" aria-label="Permalink to “cc-switch”">​</a></h2><p>Claude Code 环境中的一个命令/功能，用于在不同的 AI 模型之间快速切换。通过 cc-switch，开发者可以根据任务需求灵活选择合适的模型——例如复杂架构设计使用 V4 Pro，日常代码重构使用 V4 Flash，从而在成本、速度和能力之间取得最优平衡。</p><h2 id="claude-md" tabindex="-1">CLAUDE.md <a class="header-anchor" href="#claude-md" aria-label="Permalink to “CLAUDE.md”">​</a></h2><p>放置在项目根目录或通过 <code>claude/CLAUDE.md</code> 路径引用的 Markdown 文件，是 Claude Code 的<strong>项目记忆文件</strong>。CLAUDE.md 包含项目的架构信息、常用命令、编码规范和注意事项，Agent 在每次对话启动时自动读取，确保对项目有一致的理解。它是连接人类开发者意图与 AI 执行能力的桥梁文件。</p><h2 id="context-window-上下文窗口" tabindex="-1">Context Window / 上下文窗口 <a class="header-anchor" href="#context-window-上下文窗口" aria-label="Permalink to “Context Window / 上下文窗口”">​</a></h2><p>AI 模型单次能够处理的最大文本量（以 Token 计）。上下文窗口的大小决定了 Agent 一次对话中可以&quot;记住&quot;多少信息——包括对话历史、文件内容、工具输出和系统指令。当上下文接近窗口上限时，Agent 会触发压缩机制，将早期对话内容摘要化以释放空间。不同模型的上下文窗口大小不同，合理管理上下文是高效使用 Claude Code 的核心技能。</p><h2 id="deepseek" tabindex="-1">DeepSeek <a class="header-anchor" href="#deepseek" aria-label="Permalink to “DeepSeek”">​</a></h2><p>由中国 AI 公司深度求索（DeepSeek）开发的大语言模型系列，是 Claude Code 支持的第三方模型之一。DeepSeek 模型在代码生成和逻辑推理方面表现出色，通过 API 接入可在 Claude Code 中替代或补充 Anthropic 官方模型。其 v4 系列（DeepSeek V4）提供了与 Claude Opus/Sonnet 可比的性能水平。</p><h2 id="diff-差异对比" tabindex="-1">Diff / 差异对比 <a class="header-anchor" href="#diff-差异对比" aria-label="Permalink to “Diff / 差异对比”">​</a></h2><p>显示代码修改前后变化的技术，Claude Code 在每次编辑操作前都以 diff 格式展示拟议变更：绿色标记新增行，红色标记删除行。开发者审查 diff 后选择接受或拒绝，这是 Agent 与开发者之间最核心的交互界面之一。高质量的 diff 展示让开发者能够快速评估变更的正确性和影响范围。</p><h2 id="effort-思考投入度" tabindex="-1">Effort / 思考投入度 <a class="header-anchor" href="#effort-思考投入度" aria-label="Permalink to “Effort / 思考投入度”">​</a></h2><p>Claude Code 中控制模型思考深度的参数，影响模型在生成回复前投入的推理计算量。Effort 等级通常从低到高分为多个档位（如 Low/Medium/High），更高的投入度意味着模型会进行更深入的分析和验证，但也消耗更多 Token 和时间。开发者可根据任务复杂度选择合适的 Effort 级别——简单 CRUD 操作用低投入度，复杂算法设计用高投入度。</p><h2 id="extended-thinking-深度思考" tabindex="-1">Extended Thinking / 深度思考 <a class="header-anchor" href="#extended-thinking-深度思考" aria-label="Permalink to “Extended Thinking / 深度思考”">​</a></h2><p>Claude 模型的一项高级能力，允许模型在生成最终回复之前进行额外的内部推理步骤，类似于&quot;草稿纸&quot;机制。启用 Extended Thinking 后，模型可以分解复杂问题、验证中间结果、探索多种方案后再输出最终答案。这一功能显著提升了模型在数学推理、复杂编程和逻辑分析等任务上的表现，但会消耗更多 Token。</p><h2 id="fast-mode-快速模式" tabindex="-1">Fast Mode / 快速模式 <a class="header-anchor" href="#fast-mode-快速模式" aria-label="Permalink to “Fast Mode / 快速模式”">​</a></h2><p>Claude Code 的一种运行模式，优先追求响应速度而非思考深度。在 Fast Mode 下，Agent 减少工具调用的确认步骤、简化上下文处理、使用更快的模型变体，适合日常的简单操作如代码格式化、变量重命名、快速问答等对延迟敏感的场景。</p><h2 id="glob" tabindex="-1">Glob <a class="header-anchor" href="#glob" aria-label="Permalink to “Glob”">​</a></h2><p>一种文件路径模式匹配语法，用于在项目中按通配符规则筛选文件。Claude Code 中广泛使用 Glob 模式来指定工具操作的目标文件范围——例如 <code>src/**/*.ts</code> 匹配所有 TypeScript 源文件，<code>**/*.test.*</code> 匹配所有测试文件。与正则表达式相比，Glob 语法更简洁直观，是 Agent 进行批量文件操作时的基础工具。</p><h2 id="hook-钩子" tabindex="-1">Hook / 钩子 <a class="header-anchor" href="#hook-钩子" aria-label="Permalink to “Hook / 钩子”">​</a></h2><p>Claude Code 的事件拦截机制，允许开发者在 Agent 执行的特定时机（如工具调用前、文件修改后、会话结束前等）插入自定义脚本或命令。Hook 分为前置钩子（Pre-hook）和后置钩子（Post-hook），可用于代码格式化、安全审计、自动提交、通知发送等自动化工作流。合理的 Hook 配置让 Agent 的行为更加可控和规范。</p><h2 id="inline-edit-内联编辑" tabindex="-1">Inline Edit / 内联编辑 <a class="header-anchor" href="#inline-edit-内联编辑" aria-label="Permalink to “Inline Edit / 内联编辑”">​</a></h2><p>Claude Code 在终端/VSCode 中直接修改代码的能力，无需打开外部编辑器。Agent 定位到文件中的具体行，用替换操作精确修改代码片段，并通过 diff 展示变更供开发者确认。Inline Edit 让代码修改流程保持流畅——开发者无需在 Agent 和编辑器之间频繁切换，所有变更都在同一界面内完成。</p><h2 id="llm-large-language-model-大语言模型" tabindex="-1">LLM (Large Language Model) / 大语言模型 <a class="header-anchor" href="#llm-large-language-model-大语言模型" aria-label="Permalink to “LLM (Large Language Model) / 大语言模型”">​</a></h2><p>基于 Transformer 架构的大规模神经网络模型，通过在海量文本数据上训练获得语言理解和生成能力。LLM 是 Claude Code Agent 的&quot;大脑&quot;——它负责理解自然语言指令、推理编程问题、生成代码和解释决策。Claude（Anthropic）、GPT（OpenAI）、DeepSeek 等都属于 LLM，它们在能力、成本和使用限制上各有差异。</p><h2 id="mcp-model-context-protocol-模型上下文协议" tabindex="-1">MCP (Model Context Protocol) / 模型上下文协议 <a class="header-anchor" href="#mcp-model-context-protocol-模型上下文协议" aria-label="Permalink to “MCP (Model Context Protocol) / 模型上下文协议”">​</a></h2><p>由 Anthropic 制定的开放标准协议，定义了 AI 模型与外部工具、数据源之间的标准化交互方式。MCP 采用客户端-服务器架构：AI 应用充当 MCP 客户端，外部工具和数据源以 MCP 服务器形式接入。通过 MCP，Claude Code 可以无缝连接数据库、API、文件系统等外部资源，大幅扩展 Agent 的能力边界，同时保持接口的一致性和安全性。</p><h2 id="memory-记忆系统" tabindex="-1">Memory / 记忆系统 <a class="header-anchor" href="#memory-记忆系统" aria-label="Permalink to “Memory / 记忆系统”">​</a></h2><p>Claude Code 的长期记忆功能，允许 Agent 在多次对话之间保持对用户偏好、项目约定和历史决策的记忆。Memory 以 Markdown 文件形式存储，分为用户级和项目级两个层级。与 CLAUDE.md（静态项目知识）不同，Memory 是 Agent 在交互过程中动态积累的经验记录，随着使用时间增长而不断丰富。</p><h2 id="opus-sonnet-haiku" tabindex="-1">Opus / Sonnet / Haiku <a class="header-anchor" href="#opus-sonnet-haiku" aria-label="Permalink to “Opus / Sonnet / Haiku”">​</a></h2><p>Anthropic 旗下 Claude 模型的三个主要版本代号，按能力从高到低排列：Opus 是最强大的旗舰模型，适合复杂推理、架构设计和深度分析；Sonnet 是中等能力的均衡模型，兼顾性能与速度，适合日常开发任务；Haiku 是轻量快速模型，响应极快且成本低，适合简单问答和自动化任务。开发者可根据任务复杂度在 Claude Code 中灵活切换。</p><h2 id="plan-mode-计划模式" tabindex="-1">Plan Mode / 计划模式 <a class="header-anchor" href="#plan-mode-计划模式" aria-label="Permalink to “Plan Mode / 计划模式”">​</a></h2><p>Claude Code 的一种工作模式，Agent 在动手执行之前先生成详细的实施计划供开发者审查。计划内容包括任务分解、执行步骤、涉及的文件、潜在风险等。开发者确认计划后，Agent 再按计划逐步执行。Plan Mode 适用于大型重构、跨模块修改等高影响操作，确保开发者的意图得到准确理解后再落地。</p><h2 id="plugin-插件" tabindex="-1">Plugin / 插件 <a class="header-anchor" href="#plugin-插件" aria-label="Permalink to “Plugin / 插件”">​</a></h2><p>Claude Code 的扩展机制，允许第三方开发者为 Agent 添加新功能。插件通过标准化接口与 Agent 核心通信，可以提供自定义命令、额外工具、UI 扩展等能力。与 MCP 服务器（侧重外部数据连接）不同，插件更侧重于增强 Agent 本身的功能——例如添加新的代码分析工具、集成特定框架的脚手架命令等。</p><h2 id="prompt-提示词" tabindex="-1">Prompt / 提示词 <a class="header-anchor" href="#prompt-提示词" aria-label="Permalink to “Prompt / 提示词”">​</a></h2><p>发送给 AI 模型的输入文本，是开发者与 Agent 沟通的主要方式。提示词的质量直接影响 Agent 的输出质量——清晰、具体、包含充分上下文的提示词能引导模型生成准确的代码和方案；模糊或信息不足的提示词则容易导致偏离预期的结果。提示词工程（Prompt Engineering）是代理式编程中的核心技能。</p><h2 id="settings-json" tabindex="-1">Settings.json <a class="header-anchor" href="#settings-json" aria-label="Permalink to “Settings.json”">​</a></h2><p>Claude Code 的 JSON 格式配置文件，控制 Agent 的全局行为和权限策略。Settings 按作用域分为用户级（<code>~/.claude/settings.json</code>）、项目级（<code>.claude/settings.json</code>）和本地级（<code>.claude/settings.local.json</code>），低层级配置会覆盖高层级配置。Settings.json 中可配置权限允许列表、环境变量、Hook 和插件参数等，是实现团队规范化 Agent 行为的核心文件。</p><h2 id="skill-技能" tabindex="-1">Skill / 技能 <a class="header-anchor" href="#skill-技能" aria-label="Permalink to “Skill / 技能”">​</a></h2><p>Claude Code 中的可组合功能模块，将特定领域的工作流程封装为可复用的指令集。Skill 可以理解为&quot;预设的专业提示词 + 工具链&quot;——例如 <code>/code-review</code> Skill 自动执行代码审查流程，<code>/commit</code> Skill 引导生成规范的 commit 信息。Skill 可以由官方提供、社区贡献或开发者自定义，是提升 Agent 工作效率的重要手段。</p><h2 id="slash-command-斜杠命令" tabindex="-1">Slash Command / 斜杠命令 <a class="header-anchor" href="#slash-command-斜杠命令" aria-label="Permalink to “Slash Command / 斜杠命令”">​</a></h2><p>以 <code>/</code> 开头的快捷命令，用于触发 Claude Code 的特定功能或 Skill。例如 <code>/help</code> 显示帮助信息、<code>/compact</code> 手动触发上下文压缩、<code>/clear</code> 清空对话历史。斜杠命令提供了一种简洁高效的操作方式，减少了自然语言指令的输入成本，特别是在高频操作和紧急干预场景中尤为有用。</p><h2 id="subagent-子代理" tabindex="-1">Subagent / 子代理 <a class="header-anchor" href="#subagent-子代理" aria-label="Permalink to “Subagent / 子代理”">​</a></h2><p>Claude Code 中由主 Agent 派生出的独立工作单元，拥有独立的上下文空间和工具权限，专门处理主任务中的子任务。Subagent 可以并行执行（例如同时搜索多个文件、分别验证不同模块），完成后将结果汇总回主 Agent。这种&quot;分而治之&quot;的模式显著提升了复杂任务的执行效率，避免了单个上下文窗口的信息过载。</p><h2 id="token" tabindex="-1">Token <a class="header-anchor" href="#token" aria-label="Permalink to “Token”">​</a></h2><p>LLM 处理文本的最小计量单位，约等于英文的 0.75 个单词或中文的 1-2 个字符。Token 是计费（API 按 Token 数量收费）和上下文管理（上下文窗口以 Token 计）的基础单位。模型对输入 Token（Input Token）和输出 Token（Output Token）分别计费，且输入通常比输出便宜。理解 Token 的消耗规律有助于控制使用成本和优化上下文效率。</p><h2 id="tool-use-工具调用" tabindex="-1">Tool Use / 工具调用 <a class="header-anchor" href="#tool-use-工具调用" aria-label="Permalink to “Tool Use / 工具调用”">​</a></h2><p>Claude Code Agent 调用外部工具（如读写文件、执行命令、搜索网络、操作 Git 等）的能力，是 Agent 突破纯文本限制、与真实开发环境交互的基础。每次工具调用遵循&quot;请求-授权-执行-反馈&quot;的流程，关键操作需经开发者确认。工具调用的质量和效率直接决定了 Agent 完成实际开发任务的能力。</p><h2 id="v4-flash-v4-pro" tabindex="-1">V4 Flash / V4 Pro <a class="header-anchor" href="#v4-flash-v4-pro" aria-label="Permalink to “V4 Flash / V4 Pro”">​</a></h2><p>DeepSeek V4 系列的两个主要模型版本：V4 Flash 是轻量高速版，响应迅速且成本低，适合代码格式化、简单重构、文档生成等高频轻量任务；V4 Pro 是旗舰版，推理能力强，擅长复杂算法、系统架构设计和深度调试。两者可在 Claude Code 中通过 cc-switch 灵活切换，实现性能与成本的动态平衡。</p><h2 id="worktree" tabindex="-1">Worktree <a class="header-anchor" href="#worktree" aria-label="Permalink to “Worktree”">​</a></h2><p>Git 工作树（Worktree）是 Git 的一项功能，允许在同一仓库中同时检出多个分支到不同目录。Claude Code 集成了 Worktree 管理能力——Agent 可以自动创建隔离的工作树来执行实验性修改，完成后合并或清理。这一功能让开发者可以在不影响主工作区的情况下让 Agent 自由探索和试错，是安全使用 Agent 编码的重要保障。</p><h2 id="workflow-工作流" tabindex="-1">Workflow / 工作流 <a class="header-anchor" href="#workflow-工作流" aria-label="Permalink to “Workflow / 工作流”">​</a></h2><p>Claude Code 中将多个操作步骤串联为自动化流程的能力，通常通过 Skill、Hook 和斜杠命令组合实现。一个典型的工作流可能包括：读取需求文档 → 生成代码 → 自动测试 → 审查 diff → 生成 commit → 推送并创建 PR。合理设计的工作流能让 Agent 从&quot;单次问答工具&quot;升级为&quot;持续协作的开发伙伴&quot;。</p>',64))])}]]);export{r as __pageData,h as default};
